% MATLAB Program to Count Words in a String with Validation

% Prompt the user for input
inputString = input('Enter a string of up to 100 characters: ');

% Check if the input length exceeds 100 characters
if length(inputString) > 100
    error('Input string exceeds maximum length of 100 characters.');
end

% Define a function to validate the input string
function isValid = isValidInput(inputStr)
    % Check if the input contains only alphabetical characters, spaces, and apostrophes
    isValid = ~any(~isalpha(inputStr) && ~isspace(inputStr) && ~ismember(inputStr, ''));
end

% Validate the input
if ~isValidInput(inputString)
    error('Input contains non-alphabetical characters or apostrophes. Please re-enter the string.');
end

% Define a function to count words in the string
function wordCount = countWords(inputStr)
    % Split the string by spaces and apostrophes, then count the unique non-empty tokens
    words = split(inputStr, ' ');
    wordCount = sum(~cellfun('isempty', words));
end

% Calculate the word count
wordCount = countWords(inputString);

% Output the result
disp(['Number of words in the string: ', num2str(wordCount)]);
```

### Explanation:

