This program implements a dictionary using a Binary Search Tree (BST), allowing users to add, search, and delete words and their definitions.

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <iomanip>
#include <sstream>
#include <algorithm>

using namespace std;

// Node structure
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(const string& word, const string& definition) : word(word), definition(definition), left(nullptr), right(nullptr) {}
};

// BST operations
class BinarySearchTree {
private:
    Node* root;

    // Helper function to insert a node
    Node* insert(Node* node, const string& word, const string& definition);

    // Helper function to find a node
    Node* find(Node* node, const string& word);

    // Helper function to delete a node
    Node* deleteNode(Node* node, const string& word);

    // Helper function to print the tree
    void printTree(Node* node, int depth = 0);

public:
    BinarySearchTree() : root(nullptr) {}

    // Insert a word and its definition into the BST
    void insert(const string& word, const string& definition) {
        root = insert(root, word, definition);
    }

    // Find a word in the BST
    bool find(const string& word) {
        Node* node = find(root, word);
        return node != nullptr;
    }

    // Delete a word from the BST
    void deleteWord(const string& word) {
        root = deleteNode(root, word);
    }

    // Print the entire dictionary
    void printDictionary() {
        if (root == nullptr) {
            cout << "Dictionary is empty.\n";
            return;
        }

        cout << "Dictionary Entries:\n";
        printTree(root);
    }

    // Helper functions
    Node* insert(Node* node, const string& word, const string& definition) {
        if (node == nullptr) {
            return new Node(word, definition);
        }

        if (word < node->word) {
            node->left = insert(node->left, word, definition);
        } else if (word > node->word) {
            node->right = insert(node->right, word, definition);
        }

        return node;
    }

    Node* find(Node* node, const string& word) {
        if (node == nullptr) {
            return nullptr;
        }

        if (word == node->word) {
            return node;
        }

        if (word < node->word) {
            return find(node->left, word);
        } else {
            return find(node->right, word);
        }
    }

    Node* deleteNode(Node* node, const string& word) {
        if (node == nullptr) {
            return node;
        }

        if (word < node->word) {
            node->left = deleteNode(node->left, word);
        } else if (word > node->word) {
            node->right = deleteNode(node->right, word);
        } else {
            // Node found, delete it
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                node = temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                node = temp;
            } else {
                Node* temp = node->right;
                while (temp->left != nullptr) {
                    temp = temp->left;
                }

                node->word = temp->word;
                node->definition = temp->definition;

                node->right = deleteNode(node->right, temp->word);
            }
        }

        return node;
    }

    void printTree(Node* node, int depth = 0) {
        if (node != nullptr) {
            printTree(node->right, depth + 1);
            cout << setw(20) << left << node->word << " : " << node->definition << "\n";
            printTree(node->left, depth + 1);
        }
    }
};

int main() {
    BinarySearchTree dict;

    string word, definition;
    int choice;

    while (true) {
        cout << "\nDictionary Menu:\n";
        cout << "1. Add Word and Definition\n";
