    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST class
class BinarySearchTree {
public:
    BinarySearchTree() : root(nullptr) {}

    // Insert a new word and definition into the BST
    void insert(string word, string definition) {
        if (root == nullptr) {
            root = new Node(word, definition);
            return;
        }
        Node* current = root;
        while (true) {
            if (word < current->word) {
                if (current->left == nullptr) {
                    current->left = new Node(word, definition);
                    break;
                }
                current = current->left;
            } else {
                if (current->right == nullptr) {
                    current->right = new Node(word, definition);
                    break;
                }
                current = current->right;
            }
        }
    }

    // Search for a word in the BST
    Node* search(string word) {
        Node* current = root;
        while (current != nullptr) {
            if (word == current->word) {
                return current;
            } else if (word < current->word) {
                current = current->left;
            } else {
                current = current->right;
            }
        }
        return nullptr;
    }

    // Delete a word from the BST
    void deleteWord(string word) {
        Node* temp = root;
        Node* parent = nullptr;
        Node* toDelete = nullptr;

        // Find the node to delete
        while (temp != nullptr) {
            if (word == temp->word) {
                toDelete = temp;
                break;
            } else if (word < temp->word) {
                parent = temp;
                temp = temp->left;
            } else {
                parent = temp;
                temp = temp->right;
            }
        }

        if (toDelete == nullptr) {
            cout << "Word not found in the dictionary." << endl;
            return;
        }

        // Case 1: Node is a leaf
        if (toDelete->left == nullptr && toDelete->right == nullptr) {
            delete toDelete;
            return;
        }

        // Case 2: Node has one child
        else if (toDelete->left == nullptr) {
            // Move to the right child
            if (parent != nullptr) {
                if (parent->left == toDelete) {
                    parent->left = toDelete->right;
                } else {
                    parent->right = toDelete->right;
                }
            }
            delete toDelete;
            return;
        } else if (toDelete->right == nullptr) {
            // Move to the left child
            if (parent != nullptr) {
                if (parent->left == toDelete) {
                    parent->left = toDelete->left;
                } else {
                    parent->right = toDelete->left;
                }
            }
            delete toDelete;
            return;
        }

        // Case 3: Node has two children
        Node* leftRight = toDelete->left;
        Node* successor = leftRight;

        // Find the in-order successor (smallest in right subtree)
        while (successor->right != nullptr) {
            successor = successor->right;
        }

        // Copy the successor's value to the node to delete
        toDelete->word = successor->word;
        toDelete->definition = successor->definition;

        // Delete the successor (now a leaf)
        if (parent != nullptr) {
            if (parent->left == toDelete) {
                parent->left = successor->left;
            } else {
                parent->right = successor->left;
            }
        }
        delete successor;
    }

    // Print all words and definitions in the BST
    void printDictionary() {
        printInOrder(root);
    }

    // In-order traversal to print the dictionary
    void printInOrder(Node* node) {
        if (node != nullptr) {
            printInOrder(node->left);
            cout << node->word << " : " << node->definition << endl;
            printInOrder(node->right);
        }
    }

    // Get the root node
    Node* getRoot() const {
        return root;
    }

private:
    Node* root;
};

