}

class _ParkingFinderPageState extends State<ParkingFinderPage> {
  final GoogleMapController _mapController = GoogleMapController();
  List<ParkingSpot> spots = [];

  @override
  void initState() {
    super.initState();
    _fetchAvailableParkingSpots();
  }

