        Uri.parse('https://maps.googleapis.com/maps/api/place/nearbysearch/json?location=40.7128,-74.0060&radius=1000&key=YOUR_API_KEY&types=parking&name='),
      );

      if (response.statusCode == 200) {
        final List<dynamic> data = jsonDecode(response.body);
        if (data['results'].length > 0) {
          setState(() {
            spots = data['results'].map((e) => ParkingSpot.fromJson(e)).toList();
          });
        }
      }
    } catch (e) {
      print("Error fetching parking spots: $e");
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Parking Finder'),
      ),
      body: Column(
        children: [
          Expanded(
            child: GoogleMap(
              initialCameraPosition: CameraPosition(
                target: LatLng(40.7128, -74.0060),
                zoom: 15,
              ),
              onMapCreated: (controller) {
                _mapController = controller;
              },
              layers: [
                // Add any custom layers here
              ],
            ),
          ),
          if (spots.isNotEmpty)
            Expanded(
              child: ListView.builder(
                itemCount: spots.length,
                itemBuilder: (context, index) {
                  return ListTile(
