### Swift Binary Search Tree Implementation

Below is a clean and efficient implementation of a Binary Search Tree (BST) in Swift. The BST supports **insertion**, **deletion**, and **traversal** operations, with the ability to perform these operations in **pre-order**, **in-order**, or **post-order**.

---

### 🌟 **Key Features**:
- **BST Properties**: Left subtree contains only values less than the root, right subtree contains only values greater.
- **Insertion**: Maintains the BST property.
- **Deletion**: Removes a node while maintaining BST property.
- **Traversal**: Prints nodes in pre-order, in-order, or post-order.

---

### 📦 **Implementation Details**

```swift
// BinarySearchTree.swift
import Foundation

// Node of the Binary Search Tree
struct Node<T> {
    let value: T
    let left: Node<T>?
    let right: Node<T>?

    init(_ value: T) {
        self.value = value
        self.left = nil
        self.right = nil
    }
}

// Binary Search Tree Class
class BinarySearchTree<T> {
    var root: Node<T>?

    // Insert a new node into the BST
    func insert(_ value: T) {
        root = insertNode(root, value)
    }

    private func insertNode(_ node: Node<T>?, _ value: T) -> Node<T> {
        if node == nil {
            return Node(value)
        }

        if value < node!.value {
            node!.left = insertNode(node!.left, value)
        } else {
            node!.right = insertNode(node!.right, value)
        }

        return node!
    }

    // Delete a node from the BST
    func delete(_ value: T) {
        root = deleteNode(root, value)
    }

    private func deleteNode(_ node: Node<T>?, _ value: T) -> Node<T>? {
        if node == nil {
            return nil
        }

        if value < node!.value {
            node!.left = deleteNode(node!.left, value)
        } else if value > node!.value {
            node!.right = deleteNode(node!.right, value)
        } else {
            // Node found; delete it
            if node!.left == nil {
                return node!.right
            } else if node!.right == nil {
                return node!.left
            } else {
                // Node has two children; find the in-order successor
                let successor = findInOrderSuccessor(node!.right!)
                node!.value = successor.value
                node!.right = deleteNode(node!.right, successor.value)
            }
        }

        return node!
    }

    // Find the in-order successor
    private func findInOrderSuccessor(_ node: Node<T>?) -> Node<T>? {
        var current = node
        while current?.left != nil {
            current = current!.left
        }
        return current
    }

    // Traversal functions
    func preOrderTraverse() {
        preOrderTraverse(root)
    }

    private func preOrderTraverse(_ node: Node<T>?) {
        guard let node = node else { return }
        print(node.value, terminator: " ")
        preOrderTraverse(node.left)
    }

    func inOrderTraverse() {
        inOrderTraverse(root)
    }

    private func inOrderTraverse(_ node: Node<T>?) {
        guard let node = node else { return }
        inOrderTraverse(node.left)
        print(node.value, terminator: " ")
        inOrderTraverse(node.right)
    }

    func postOrderTraverse() {
        postOrderTraverse(root)
    }

    private func postOrderTraverse(_ node: Node<T>?) {
        guard let node = node else { return }
        postOrderTraverse(node.left)
        postOrderTraverse(node.right)
        print(node.value, terminator: " ")
    }
}
```

