Here's a well-structured JavaScript program that implements a binary search algorithm to search for a specific value in a sorted array:

```javascript
function binarySearch(arr, target) {
    let left = 0;
    let right = arr.length - 1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);

        if (arr[mid] === target) {
            return mid; // Target found at index mid
        } else if (arr[mid] < target) {
            left = mid + 1; // Target is on the right
        } else {
            right = mid - 1; // Target is on the left
        }
    }

    return -1; // Target not found
}

// Example usage:
